import { getRequestHeaders, type H3Event } from 'h3'
import { checksums } from '#content/manifest'

async function fetchContent<T>(
  event: H3Event | undefined,
  collection: string,
  path: string,
  options: NonNullable<Parameters<typeof $fetch>[1]>,
): Promise<T> {
  const headers = event ? getRequestHeaders(event) : {}
  headers['accept-encoding'] = undefined // prevent unsupported enconding issue (https://github.com/nuxt/content/pull/3701)

  const url = `/__nuxt_content/${collection}/${path}`
  const fetchOptions = {
    ...options,
    headers: {
      ...headers,
      ...options.headers,
    },
    query: { v: checksums[String(collection)], t: import.meta.dev ? Date.now() : undefined },
  }
  return event ? await event.$fetch(url, fetchOptions) : await $fetch(url, fetchOptions)
}

export async function fetchDatabase(event: H3Event | undefined, collection: string): Promise<string> {
  return fetchContent(event, collection, 'sql_dump.txt', {
    responseType: 'text',
    headers: {
      'content-type': 'text/plain',
    },
  })
}

export async function fetchQuery<Item>(event: H3Event | undefined, collection: string, sql: string): Promise<Item[]> {
  return fetchContent(event, collection, 'query', {
    headers: {
      'content-type': 'application/json',
    },
    method: 'POST',
    body: {
      sql,
    },
  })
}

import { createContext } from 'unctx'

type ContextKey = 'zod3' | 'zod4' | 'valibot' | 'unknown'

const nuxtContentContext = {
  zod3: {
    toJSONSchema: (_schema: unknown, _name: string) => {
      throw new Error(
        'It seems you are using Zod version 3 for collection schema, but Zod is not installed, '
        + 'Nuxt Content does not ship with zod, install `zod` and `zod-to-json-schema` and it will work.',
      )
    },
  },
  zod4: {
    toJSONSchema: (_schema: unknown, _name: string) => {
      throw new Error(
        'It seems you are using Zod version 4 for collection schema, but Zod is not installed, '
        + 'Nuxt Content does not ship with zod, install `zod` and it will work.',
      )
    },
  },
  valibot: {
    toJSONSchema: (_schema: unknown, _name: string) => {
      throw new Error(
        'It seems you are using Valibot for collection schema, but Valibot is not installed, '
        + 'Nuxt Content does not ship with valibot, install `valibot` and `@valibot/to-json-schema` and it will work.',
      )
    },
  },
  unknown: {
    toJSONSchema: (_schema: unknown, _name: string) => {
      throw new Error('Unknown schema vendor')
    },
  },
  set: (key: ContextKey, value: unknown) => {
    nuxtContentContext[key] = value as typeof nuxtContentContext[ContextKey]
  },
  get: (key: ContextKey) => {
    return nuxtContentContext[key]
  },
}

const ctx = createContext<typeof nuxtContentContext>()
ctx.set(nuxtContentContext)

export default ctx.use

import { AST_NODE_TYPES } from '@typescript-eslint/types'
import { createRule } from '../utils'

type MessageIds = 'default'

type Options = []

const processSuffixes = new Set([
  'client',
  'browser',
  'server',
  'nitro',
  'dev',
  'test',
  'prerender',
])

export const rule = createRule<MessageIds, Options>({
  name: 'prefer-import-meta',
  meta: {
    type: 'suggestion',
    docs: {
      description: 'Prefer using `import.meta.*` over `process.*`',
    },
    schema: [],
    messages: {
      default: 'Replace `process.{{ suffix }}` with `import.meta.{{ suffix }}`.',
    },
    fixable: 'code',
  },
  defaultOptions: [],
  create: context => ({
    MemberExpression: (node) => {
      if (
        node.object.type === AST_NODE_TYPES.Identifier
        && node.object.name === 'process'
        && node.property.type === AST_NODE_TYPES.Identifier
        && processSuffixes.has(node.property.name)
      ) {
        const suffix = node.property.name

        context.report({
          node,
          messageId: 'default',
          data: {
            suffix,
          },
          fix: fixer => fixer.replaceText(node, `import.meta.${suffix}`),
        })
      }
    },
  }),
})

import type { H3Event } from 'nitro/h3'
import { useRuntimeConfig } from 'nitro/runtime-config'
import { createHead } from '@unhead/vue/server'
import type { NuxtPayload, NuxtSSRContext } from 'nuxt/app'
import { sharedPrerenderCache } from '../cache'
// @ts-expect-error virtual file
import unheadOptions from '#internal/unhead-options.mjs'
// @ts-expect-error virtual file
import { NUXT_NO_SSR, NUXT_SHARED_DATA } from '#internal/nuxt/nitro-config.mjs'

const PRERENDER_NO_SSR_ROUTES = new Set(['/index.html', '/200.html', '/404.html'])

export function createSSRContext (event: H3Event): NuxtSSRContext {
  const url = event.url.pathname + event.url.search + event.url.hash
  const ssrContext: NuxtSSRContext = {
    url,
    event,
    runtimeConfig: useRuntimeConfig() as NuxtSSRContext['runtimeConfig'],
    noSSR: !!(NUXT_NO_SSR) || event.context.nuxt?.noSSR || (import.meta.prerender ? PRERENDER_NO_SSR_ROUTES.has(url) : false),
    head: createHead(unheadOptions),
    error: false,
    nuxt: undefined!, /* NuxtApp */
    payload: {},
    ['~payloadReducers']: Object.create(null),
    modules: new Set(),
  }

  if (import.meta.prerender) {
    if (NUXT_SHARED_DATA) {
      ssrContext['~sharedPrerenderCache'] = sharedPrerenderCache!
    }
    ssrContext.payload.prerenderedAt = Date.now()
  }

  return ssrContext
}

export function setSSRError (ssrContext: NuxtSSRContext, error: NuxtPayload['error'] & { url: string }): void {
  ssrContext.error = true
  ssrContext.payload = { error }
  const url = new URL(error.url)
  ssrContext.url = url.pathname + url.search + url.hash
}

import type { Nuxt } from '../types/nuxt.ts'
import { type ResolverGetter, defineResolvers } from '../utils/definition.ts'

type ServerBuilder = '@nuxt/nitro-server' | (string & {}) | { bundle: (nuxt: Nuxt) => Promise<void> }

export default defineResolvers({
  server: {
    builder: {
      $resolve: (val: unknown): ServerBuilder => {
        if (typeof val === 'string') {
          return val
        }
        if (val && typeof val === 'object' && 'bundle' in val) {
          return val as { bundle: (nuxt: Nuxt) => Promise<void> }
        }
        return '@nuxt/nitro-server'
      },
    },
  },
  nitro: {
    runtimeConfig: {
      $resolve: async (val: unknown, get: ResolverGetter) => {
        const runtimeConfig = await get('runtimeConfig')
        return {
          ...runtimeConfig,
          app: {
            ...runtimeConfig.app,
            baseURL: runtimeConfig.app.baseURL.startsWith('./')
              ? runtimeConfig.app.baseURL.slice(1)
              : runtimeConfig.app.baseURL,
          },
          nitro: {
            envPrefix: 'NUXT_',
            ...runtimeConfig.nitro,
          },
        }
      },
    },
    routeRules: {
      $resolve: async (val: unknown, get: ResolverGetter) => {
        return {
          ...await get('routeRules'),
          ...(val && typeof val === 'object' ? val : {}),
        }
      },
    },
  },
  routeRules: {},
  serverHandlers: [],
  devServerHandlers: [],
})

import { runInNewContext } from 'node:vm'
import { join, resolve } from 'node:path'
import { fileURLToPath } from 'node:url'
import { promises as fsp } from 'node:fs'
import type { Plugin } from 'vite'
import genericMessages from '../templates/messages.json' with { type: 'json' }
import pkg from '../../nuxt/package.json' with { type: 'json' }

const templatesRoot = fileURLToPath(new URL('..', import.meta.url))

const r = (...path: string[]) => resolve(join(templatesRoot, ...path))

export const DevRenderingPlugin = () => {
  return <Plugin>{
    name: 'dev-rendering',
    async transformIndexHtml (html: string, context) {
      const page = context.originalUrl || '/'

      if (page.endsWith('.png')) { return }

      if (page === '/') {
        const templateNames = await fsp.readdir(r('templates'))
        const serializedData = JSON.stringify({ templateNames })
        return html.replace('{{ data }}', serializedData)
      }

      const contents = await fsp.readFile(r(page, 'index.html'), 'utf-8')

      const messages = JSON.parse(await fsp.readFile(r(page, 'messages.json'), 'utf-8'))

      const chunks = contents.split(/\{{2,3}[^{}]+\}{2,3}/)
      let templateString = chunks.shift()
      for (const expression of contents.matchAll(/\{{2,3}([^{}]+)\}{2,3}/g)) {
        const value = runInNewContext(expression[1]!.trim(), {
          version: pkg.version,
          messages: { ...genericMessages, ...messages },
        })
        templateString += `${value}${chunks.shift()}`
      }
      if (chunks.length > 0) {
        templateString += chunks.join('')
      }

      return templateString
    },
  }
}

import process from 'node:process'
import { execFileSync } from 'node:child_process'
import { inc } from 'semver'
import { determineBumpType, getLatestTag, loadWorkspace } from './_utils.ts'

const nightlyPackages = {
  // nitro: 'nitro-nightly',
  // h3: 'h3-nightly',
  'nuxi': 'nuxi-nightly',
  '@nuxt/cli': '@nuxt/cli-nightly',
}

export async function bumpNightly () {
  const workspace = await loadWorkspace(process.cwd())

  const commit = execFileSync('git', ['rev-parse', '--short', 'HEAD'], { encoding: 'utf-8' }).trim().slice(0, 8)
  const date = Math.round(Date.now() / (1000 * 60))

  // TODO: revert after release of v4.2.0
  // Get the date of the latest tag to filter out merged history commits
  const latestTagName = await getLatestTag()
  const tagDate = execFileSync('git', ['log', '-1', '--format=%ai', latestTagName], { encoding: 'utf-8' })
  const sinceDate = tagDate.trim()

  const bumpType = await determineBumpType(sinceDate)

  for (const pkg of workspace.packages.filter(p => !p.data.private)) {
    const newVersion = inc(pkg.data.version, bumpType || 'patch')
    if (!newVersion) {
      throw new Error(`Failed to increment version for package ${pkg.data.name} with version ${pkg.data.version}`)
    }

    workspace.setVersion(pkg.data.name, `${newVersion}-${date}.${commit}`, {
      updateDeps: true,
    })
    for (const [name, nightlyName] of Object.entries(nightlyPackages)) {
      if (pkg.data.dependencies && name in pkg.data.dependencies) {
        pkg.data.dependencies[name] = `npm:${nightlyName}@latest`
      }
    }
    const newname = pkg.data.name + '-nightly'
    workspace.rename(pkg.data.name, newname)
  }

  await workspace.save()
}

